-- ============================================================
-- seed_demo_reviews.sql
-- 155 demo reviews across 50 cleaners
-- Distribution: ~60% 5-star, ~25% 4-star, ~10% 3-star, ~5% 1-2 star
-- ============================================================

SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

INSERT INTO `reviews` (`cleaner_id`, `user_id`, `author_name`, `author_email`, `rating`, `title`, `content`, `status`, `is_verified`, `created_at`) VALUES

-- ============================================================
-- Sunshine Roofing Co. (12 reviews: 8x5, 3x4, 1x3)
-- ============================================================
((SELECT id FROM cleaners WHERE slug = 'sunshine-roofing-co'), NULL, 'Jennifer Adams', 'jadams@email.com', 5, 'Excellent roof replacement', 'Carlos and his team replaced our entire tile roof after Hurricane Irma damage. They handled our insurance claim paperwork and completed the work in just four days. The roof looks amazing and we haven''t had a single leak since.', 'approved', 1, '2025-08-15 10:30:00'),
((SELECT id FROM cleaners WHERE slug = 'sunshine-roofing-co'), NULL, 'Robert Chen', 'rchen@email.com', 5, 'Professional and fast', 'Had a major leak during a storm and Sunshine Roofing came out the same day. They tarped the roof immediately and scheduled the full repair for the following week. Great communication throughout the entire process.', 'approved', 1, '2025-09-02 14:15:00'),
((SELECT id FROM cleaners WHERE slug = 'sunshine-roofing-co'), NULL, 'Lisa Martinez', 'lmartinez@email.com', 5, 'Best roofing company in Miami', 'We got quotes from five different roofers and Sunshine offered the best value. Their crew was hardworking, respectful, and cleaned up everything when they were done. Highly recommend to anyone in South Florida.', 'approved', 1, '2025-09-20 09:45:00'),
((SELECT id FROM cleaners WHERE slug = 'sunshine-roofing-co'), NULL, 'Thomas Walker', 'twalker@email.com', 4, 'Good work, minor delay', 'The quality of the roof installation is excellent and we are very happy with the final result. Only reason for four stars is the project started two days later than originally scheduled due to a parts delay.', 'approved', 1, '2025-10-05 16:00:00'),
((SELECT id FROM cleaners WHERE slug = 'sunshine-roofing-co'), NULL, 'Amanda Foster', 'afoster@email.com', 5, 'Trustworthy and skilled', 'Sunshine Roofing diagnosed a ventilation problem that two other companies missed. They fixed the issue and our attic is noticeably cooler now. Fair pricing and honest assessment of what we actually needed.', 'approved', 1, '2025-10-18 11:20:00'),
((SELECT id FROM cleaners WHERE slug = 'sunshine-roofing-co'), NULL, 'David Park', 'dpark@email.com', 5, 'Outstanding storm repair', 'After a bad thunderstorm knocked off some tiles, these guys were on my roof the next morning. Quick, thorough, and the repair is seamless. You can''t even tell where the damage was.', 'approved', 1, '2025-11-01 08:45:00'),
((SELECT id FROM cleaners WHERE slug = 'sunshine-roofing-co'), NULL, 'Sarah Mitchell', 'smitchell@email.com', 4, 'Very satisfied', 'They replaced our old shingle roof with a beautiful new tile roof. The transformation is incredible and our neighbors keep asking who we used. Communication could have been slightly better during the project.', 'approved', 1, '2025-11-15 13:30:00'),
((SELECT id FROM cleaners WHERE slug = 'sunshine-roofing-co'), NULL, 'Kevin Brooks', 'kbrooks@email.com', 5, 'Five stars all around', 'From the initial estimate to the final inspection, Sunshine Roofing was professional and transparent. The crew leader explained every step of the process and the workmanship is top-notch.', 'approved', 1, '2025-12-03 10:00:00'),
((SELECT id FROM cleaners WHERE slug = 'sunshine-roofing-co'), NULL, 'Patricia Young', 'pyoung@email.com', 5, 'Highly recommend', 'We hired them for a complete re-roof and they delivered exactly what was promised. Great attention to detail on the flashing and ventilation. Clean worksite every evening.', 'approved', 1, '2025-12-20 15:45:00'),
((SELECT id FROM cleaners WHERE slug = 'sunshine-roofing-co'), NULL, 'Brian Turner', 'bturner@email.com', 4, 'Solid roofing work', 'Good quality installation of architectural shingles on our home. The price was competitive and the 10-year workmanship warranty gives us great peace of mind.', 'approved', 1, '2026-01-08 09:15:00'),
((SELECT id FROM cleaners WHERE slug = 'sunshine-roofing-co'), NULL, 'Nancy White', 'nwhite@email.com', 5, 'Saved us from a disaster', 'Discovered our roof decking was rotting during what we thought would be a simple repair. They showed us photos, explained the options, and replaced the damaged sections without trying to upsell us on a full roof.', 'approved', 1, '2026-01-22 12:00:00'),
((SELECT id FROM cleaners WHERE slug = 'sunshine-roofing-co'), NULL, 'Mark Phillips', 'mphillips@email.com', 3, 'Decent but took longer than expected', 'The final result is good and the roof looks nice. However, the project took eight days instead of the estimated five. Workers were friendly but the scheduling could be improved.', 'approved', 1, '2026-02-05 14:30:00'),

-- ============================================================
-- Metro Plumbing Solutions (8 reviews: 5x5, 2x4, 1x3)
-- ============================================================
((SELECT id FROM cleaners WHERE slug = 'metro-plumbing-solutions'), NULL, 'Angela Rivera', 'arivera@email.com', 5, 'Fixed our burst pipe fast', 'Pipe burst in our kitchen at 11 PM and Metro had a plumber at our door within 45 minutes. He stopped the flooding, repaired the pipe, and helped us clean up. Absolute lifesaver.', 'approved', 1, '2025-08-22 23:30:00'),
((SELECT id FROM cleaners WHERE slug = 'metro-plumbing-solutions'), NULL, 'William Foster', 'wfoster@email.com', 5, 'Great water heater install', 'James and his team replaced our old 40-gallon tank with a tankless system. They explained the energy savings we could expect and the installation was completed in one day. Very professional.', 'approved', 1, '2025-09-10 11:00:00'),
((SELECT id FROM cleaners WHERE slug = 'metro-plumbing-solutions'), NULL, 'Christine Hall', 'chall@email.com', 4, 'Good service, honest pricing', 'Called them for a clogged shower drain and the plumber was upfront about the cost before starting any work. Fixed the issue in about 30 minutes. Will definitely call again.', 'approved', 1, '2025-10-15 08:30:00'),
((SELECT id FROM cleaners WHERE slug = 'metro-plumbing-solutions'), NULL, 'Daniel Brown', 'dbrown@email.com', 5, 'Bathroom plumbing done right', 'Metro Plumbing handled all the rough-in plumbing for our bathroom renovation. Everything was done to code and they coordinated perfectly with our general cleaner. No issues at inspection.', 'approved', 1, '2025-11-08 13:45:00'),
((SELECT id FROM cleaners WHERE slug = 'metro-plumbing-solutions'), NULL, 'Rachel Green', 'rgreen@email.com', 5, 'Reliable and reasonably priced', 'We have used Metro Plumbing three times now for various repairs and they have been excellent every time. Consistent quality, fair prices, and they always show up when they say they will.', 'approved', 1, '2025-12-01 10:15:00'),
((SELECT id FROM cleaners WHERE slug = 'metro-plumbing-solutions'), NULL, 'Gary Adams', 'gadams@email.com', 4, 'Solved a tricky drain issue', 'Had a recurring drain clog that another plumber couldn''t fix. Metro used a camera to find tree roots in the line and cleared them out with a hydro jet. Problem solved for good.', 'approved', 1, '2025-12-18 15:00:00'),
((SELECT id FROM cleaners WHERE slug = 'metro-plumbing-solutions'), NULL, 'Stephanie Lee', 'slee@email.com', 5, 'Emergency service when we needed it', 'Our toilet overflowed on a Saturday evening and they came within an hour. Fixed the issue quickly and the plumber was very polite and cleaned up after himself.', 'approved', 1, '2026-01-12 18:30:00'),
((SELECT id FROM cleaners WHERE slug = 'metro-plumbing-solutions'), NULL, 'Howard Clark', 'hclark@email.com', 3, 'Took a while to get an appointment', 'The actual plumbing work was good quality, but it took over a week to get scheduled for a non-emergency repair. Once they arrived, the plumber was knowledgeable and efficient.', 'approved', 1, '2026-02-01 09:00:00'),

-- ============================================================
-- Coastal Kitchen & Bath (10 reviews: 7x5, 2x4, 1x3)
-- ============================================================
((SELECT id FROM cleaners WHERE slug = 'coastal-kitchen-and-bath'), NULL, 'Michelle Thompson', 'mthompson@email.com', 5, 'Dream kitchen came true', 'Maria and her design team completely transformed our dated kitchen into a modern masterpiece. The quartz countertops, soft-close cabinets, and tile backsplash are absolutely gorgeous. Worth every penny.', 'approved', 1, '2025-08-10 14:00:00'),
((SELECT id FROM cleaners WHERE slug = 'coastal-kitchen-and-bath'), NULL, 'Jeffrey Scott', 'jscott@email.com', 5, 'Stunning bathroom renovation', 'Our master bathroom went from an 80s disaster to a spa-like retreat. The frameless glass shower, heated floors, and freestanding tub are exactly what we wanted. The team was meticulous about every detail.', 'approved', 1, '2025-09-05 11:30:00'),
((SELECT id FROM cleaners WHERE slug = 'coastal-kitchen-and-bath'), NULL, 'Laura Anderson', 'landerson@email.com', 5, 'Best remodeler in Broward', 'This is the second time we have used Coastal Kitchen & Bath and both experiences have been outstanding. They just finished our guest bathroom and it looks like something out of a magazine.', 'approved', 1, '2025-09-25 16:45:00'),
((SELECT id FROM cleaners WHERE slug = 'coastal-kitchen-and-bath'), NULL, 'Charles Wright', 'cwright@email.com', 4, 'Beautiful kitchen, slight delay', 'The finished kitchen is absolutely beautiful and the quality of the cabinetry is exceptional. The project ran about 10 days over the original timeline, but the end result made the wait worthwhile.', 'approved', 1, '2025-10-12 10:00:00'),
((SELECT id FROM cleaners WHERE slug = 'coastal-kitchen-and-bath'), NULL, 'Diana Patel', 'dpatel@email.com', 5, 'Outstanding design and execution', 'Their designer helped us maximize our small kitchen space in ways we never imagined. The layout is so much more functional now and the modern design makes the room feel twice as big.', 'approved', 1, '2025-11-03 13:15:00'),
((SELECT id FROM cleaners WHERE slug = 'coastal-kitchen-and-bath'), NULL, 'George Kim', 'gkim@email.com', 5, 'Exceeded our expectations', 'We hired them to remodel both our kitchen and master bath. The coordination between the two projects was seamless and the quality of work is exceptional. Our home feels brand new.', 'approved', 1, '2025-11-20 09:30:00'),
((SELECT id FROM cleaners WHERE slug = 'coastal-kitchen-and-bath'), NULL, 'Karen Fisher', 'kfisher@email.com', 5, 'Professional from start to finish', 'The entire process was smooth from the initial design meeting to the final walkthrough. They protected our floors, cleaned up daily, and the finished bathroom is absolutely stunning.', 'approved', 1, '2025-12-08 15:30:00'),
((SELECT id FROM cleaners WHERE slug = 'coastal-kitchen-and-bath'), NULL, 'Ryan Nelson', 'rnelson@email.com', 4, 'Great craftsmanship', 'Really happy with our new kitchen countertops and tile work. The installation crew was skilled and careful. Minor communication gaps with scheduling but overall a very positive experience.', 'approved', 1, '2025-12-28 12:00:00'),
((SELECT id FROM cleaners WHERE slug = 'coastal-kitchen-and-bath'), NULL, 'Samantha Cruz', 'scruz@email.com', 5, 'Worth the investment', 'We compared several remodeling companies and chose Coastal for their portfolio and reviews. They delivered exactly the high-end kitchen renovation we were looking for. Absolutely love it.', 'approved', 1, '2026-01-15 10:45:00'),
((SELECT id FROM cleaners WHERE slug = 'coastal-kitchen-and-bath'), NULL, 'Thomas Reed', 'treed@email.com', 3, 'Good quality but over budget', 'The workmanship is excellent and our bathroom looks great. However, several change orders during the project pushed the final cost about 15% over the original estimate. Make sure to budget extra.', 'approved', 1, '2026-02-02 14:00:00'),

-- ============================================================
-- Florida Comfort HVAC (7 reviews: 4x5, 2x4, 1x2)
-- ============================================================
((SELECT id FROM cleaners WHERE slug = 'florida-comfort-hvac'), NULL, 'Jessica Morgan', 'jmorgan@email.com', 5, 'New AC works perfectly', 'Our 15-year-old AC finally gave out in July and Florida Comfort had a new Carrier system installed within two days. The house is cool again and our electric bill dropped by about $60 a month.', 'approved', 1, '2025-08-25 11:00:00'),
((SELECT id FROM cleaners WHERE slug = 'florida-comfort-hvac'), NULL, 'Marcus Johnson', 'mjohnson@email.com', 5, 'Same-day AC repair', 'AC stopped blowing cold air on a 95-degree day. Their tech arrived within three hours, diagnosed a bad capacitor, and had it replaced in under an hour. Back to cool in no time.', 'approved', 1, '2025-09-30 16:30:00'),
((SELECT id FROM cleaners WHERE slug = 'florida-comfort-hvac'), NULL, 'Emily Davis', 'edavis@email.com', 4, 'Good maintenance service', 'We signed up for their annual maintenance plan and the technician was thorough during the tune-up. He found a small refrigerant leak and fixed it before it became a bigger problem.', 'approved', 1, '2025-10-22 09:00:00'),
((SELECT id FROM cleaners WHERE slug = 'florida-comfort-hvac'), NULL, 'Vincent Rossi', 'vrossi@email.com', 5, 'Excellent duct cleaning', 'Had our ducts cleaned and what they pulled out was shocking. The air quality in our home improved immediately and my allergies have been much better since. Very thorough job.', 'approved', 1, '2025-11-14 13:45:00'),
((SELECT id FROM cleaners WHERE slug = 'florida-comfort-hvac'), NULL, 'Carol Sanders', 'csanders@email.com', 4, 'Reliable and knowledgeable', 'David''s team installed a new heat pump system in our home. They explained the pros and cons of different options and helped us choose the right size system. Good value for the money.', 'approved', 1, '2025-12-10 10:30:00'),
((SELECT id FROM cleaners WHERE slug = 'florida-comfort-hvac'), NULL, 'Nathan Price', 'nprice@email.com', 5, 'Fixed it right the first time', 'Multiple companies couldn''t figure out why our AC kept short-cycling. Florida Comfort found a bad expansion valve on the first visit. AC has been running perfectly ever since.', 'approved', 1, '2026-01-05 14:15:00'),
((SELECT id FROM cleaners WHERE slug = 'florida-comfort-hvac'), NULL, 'Diana Cooper', 'dcooper@email.com', 2, 'Expensive repair', 'The technician was knowledgeable but the repair bill was significantly higher than what I was quoted on the phone. I felt pressured into additional services that may not have been necessary.', 'approved', 1, '2026-01-28 11:00:00'),

