((SELECT id FROM cleaners WHERE slug = 'palm-city-electrical'), NULL, 'Robert Harris', 'rharris@email.com', 5, 'Panel upgrade done professionally', 'Needed to upgrade from a 100-amp to 200-amp panel for our home office. The electrician was incredibly knowledgeable, pulled all permits, and passed inspection on the first try.', 'approved', 1, '2025-09-15 10:00:00'),
((SELECT id FROM cleaners WHERE slug = 'palm-city-electrical'), NULL, 'Amy Peterson', 'apeterson@email.com', 5, 'Smart home wiring experts', 'They wired our entire house for a smart home system including automated lighting, motorized blinds, and a whole-house audio system. Everything works flawlessly and the wiring is immaculate.', 'approved', 1, '2025-11-10 14:30:00'),
((SELECT id FROM cleaners WHERE slug = 'palm-city-electrical'), NULL, 'Frank Rodriguez', 'frodriguez@email.com', 4, 'Good work on generator install', 'Had a whole-house Generac generator installed and the team did a solid job. They handled the gas line, electrical connections, and city permit. Only took three days start to finish.', 'approved', 1, '2025-12-15 09:45:00'),
((SELECT id FROM cleaners WHERE slug = 'palm-city-electrical'), NULL, 'Beth Young', 'byoung@email.com', 5, 'Emergency repair at midnight', 'Half our house lost power at midnight and Palm City had an electrician out within an hour. Turned out to be a failed breaker. Quick fix and they only charged a reasonable emergency fee.', 'approved', 1, '2026-01-10 00:30:00'),
