((SELECT id FROM cleaners WHERE slug = 'tampa-bay-bath-remodeling'), NULL, 'Kelly Adams', 'kadams@email.com', 5, 'Beautiful walk-in shower', 'They converted our old tub into a gorgeous walk-in shower with a rain head and bench. The tile work is perfect and the frameless glass door really opens up the space. Done in just six days.', 'approved', 1, '2025-09-08 12:00:00'),
