((SELECT id FROM cleaners WHERE slug = 'first-coast-general-contracting'), NULL, 'Jerome Walker', 'jwalker@email.com', 5, 'True professionals', 'From the detailed proposal to the final punch list walkthrough, this company operates at a high level. Their project manager kept us informed at every stage and the quality speaks for itself.', 'approved', 1, '2025-12-12 15:30:00'),
((SELECT id FROM cleaners WHERE slug = 'first-coast-general-contracting'), NULL, 'Monica Reed', 'mreed@email.com', 4, 'Great results, minor delays', 'The whole-house renovation turned out beautifully. There were some scheduling delays with subcleaners but the GC managed them well and the final quality was excellent.', 'approved', 1, '2026-01-04 11:45:00'),
