-- ============================================================
((SELECT id FROM cleaners WHERE slug = 'bay-area-roofing-pros'), NULL, 'Catherine Lee', 'clee@email.com', 5, 'The best roofer in the Bay Area', 'William and his team replaced the slate roof on our Victorian home and it looks spectacular. They sourced matching slate tiles and the craftsmanship is museum-quality. Could not be happier.', 'approved', 1, '2025-08-05 10:00:00'),
((SELECT id FROM cleaners WHERE slug = 'bay-area-roofing-pros'), NULL, 'Andrew Watson', 'awatson@email.com', 5, 'Flat roof experts', 'Had a persistent leak on our flat commercial roof that three other companies couldn''t fix. Bay Area Roofing found the problem in 20 minutes and installed a new TPO membrane. Leak gone forever.', 'approved', 1, '2025-08-28 14:30:00'),
((SELECT id FROM cleaners WHERE slug = 'bay-area-roofing-pros'), NULL, 'Margaret Chen', 'mchen@email.com', 5, 'Incredible green roof', 'They installed a green roof system on our eco-friendly office building. The plants are thriving and our energy bills have dropped. A truly unique offering in the Bay Area.', 'approved', 1, '2025-09-12 09:00:00'),
((SELECT id FROM cleaners WHERE slug = 'bay-area-roofing-pros'), NULL, 'Scott Wilson', 'swilson@email.com', 4, 'Excellent quality work', 'New composition shingle roof looks great and was installed quickly. The price was a bit higher than some quotes we received, but the workmanship and warranty justify the investment.', 'approved', 1, '2025-09-28 12:15:00'),
((SELECT id FROM cleaners WHERE slug = 'bay-area-roofing-pros'), NULL, 'Diana Foster', 'dfoster@email.com', 5, 'Saved our home from water damage', 'Found extensive hidden water damage during a routine inspection. They repaired all the damaged decking before installing the new roof and probably saved us tens of thousands in future repairs.', 'approved', 1, '2025-10-15 16:00:00'),
((SELECT id FROM cleaners WHERE slug = 'bay-area-roofing-pros'), NULL, 'John Mitchell', 'jmitchell@email.com', 5, 'Professional crew, great results', 'Five-man crew completed our re-roof in three days. They were organized, efficient, and left our yard cleaner than they found it. The new architectural shingles look stunning.', 'approved', 1, '2025-10-30 10:45:00'),
((SELECT id FROM cleaners WHERE slug = 'bay-area-roofing-pros'), NULL, 'Rachel Kim', 'rkim@email.com', 4, 'Very good experience overall', 'Had some skylights added along with a new roof. The integration is seamless and the natural light in our home is wonderful now. Minor scheduling hiccup but nothing major.', 'approved', 1, '2025-11-18 14:00:00'),
((SELECT id FROM cleaners WHERE slug = 'bay-area-roofing-pros'), NULL, 'Michael Santos', 'msantos@email.com', 5, 'Top-notch tile roofing', 'They installed a clay tile roof on our Mediterranean-style home. The attention to detail on the ridge caps and valleys is exceptional. This roof will last a lifetime.', 'approved', 1, '2025-12-02 11:30:00'),
((SELECT id FROM cleaners WHERE slug = 'bay-area-roofing-pros'), NULL, 'Laura Peters', 'lpeters@email.com', 5, 'Repeat customer, always happy', 'This is the third property where I have used Bay Area Roofing. Consistently excellent work, transparent pricing, and they stand behind their warranty. The gold standard for roofers.', 'approved', 1, '2025-12-18 09:15:00'),
((SELECT id FROM cleaners WHERE slug = 'bay-area-roofing-pros'), NULL, 'Brandon Hill', 'bhill@email.com', 5, 'Emergency tarping saved us', 'Tree fell on our roof during a windstorm and they had a tarp on it within two hours. The permanent repair was scheduled the following week and done perfectly. Grateful for their fast response.', 'approved', 1, '2026-01-06 08:00:00'),
((SELECT id FROM cleaners WHERE slug = 'bay-area-roofing-pros'), NULL, 'Susan Taylor', 'staylor@email.com', 4, 'Solid commercial roofing', 'They replaced the EPDM roof on our warehouse. The work was done on weekends to avoid disrupting our business operations. Good communication and quality work.', 'approved', 1, '2026-01-15 13:00:00'),
((SELECT id FROM cleaners WHERE slug = 'bay-area-roofing-pros'), NULL, 'Allen Davis', 'adavis@email.com', 5, 'Best warranty in the business', 'They offer a 10-year workmanship warranty on top of the manufacturer warranty. That level of confidence in their work says a lot. The roof looks amazing too.', 'approved', 1, '2026-01-25 10:30:00'),
((SELECT id FROM cleaners WHERE slug = 'bay-area-roofing-pros'), NULL, 'Jennifer White', 'jwhite@email.com', 5, 'Outstanding service', 'Bay Area Roofing Pros is the most professional roofing company we have ever worked with. From the drone inspection to the final walkthrough, every step was handled with care.', 'approved', 1, '2026-02-01 15:00:00'),
((SELECT id FROM cleaners WHERE slug = 'bay-area-roofing-pros'), NULL, 'Robert Brown', 'rbrown2@email.com', 4, 'Good roof, fair price', 'Replaced our 25-year-old roof with new 30-year architectural shingles. The crew was hardworking and efficient. Price was middle of the road compared to other quotes.', 'approved', 1, '2026-02-08 11:00:00'),
((SELECT id FROM cleaners WHERE slug = 'bay-area-roofing-pros'), NULL, 'Elizabeth Moore', 'emoore@email.com', 3, 'Work quality is great, communication could improve', 'The roof itself is perfect and looks beautiful. My only complaint is that it was sometimes hard to get return calls from the office. The field crew was excellent though.', 'approved', 1, '2026-02-14 09:30:00'),

