-- Pacific Plumbing & Drain (11 reviews: 7x5, 3x4, 1x1)
-- ============================================================
((SELECT id FROM cleaners WHERE slug = 'pacific-plumbing-and-drain'), NULL, 'Victoria Chang', 'vchang@email.com', 5, 'Sewer line replacement done right', 'Pacific Plumbing replaced our entire sewer line using trenchless technology. Minimal disruption to our yard and the job was done in two days. They even patched the small access hole perfectly.', 'approved', 1, '2025-08-12 10:30:00'),
((SELECT id FROM cleaners WHERE slug = 'pacific-plumbing-and-drain'), NULL, 'Ronald West', 'rwest@email.com', 5, 'Whole house repiping', 'Our 1960s home had original galvanized pipes that were corroding. Daniel and his crew repiped the entire house with PEX in three days. Water pressure is incredible now.', 'approved', 1, '2025-09-08 14:00:00'),
((SELECT id FROM cleaners WHERE slug = 'pacific-plumbing-and-drain'), NULL, 'Megan Park', 'mpark@email.com', 4, 'Fast and professional', 'Called for a clogged kitchen drain and the plumber had it cleared within an hour. He also checked the other drains while he was here at no extra charge. Good service.', 'approved', 1, '2025-09-25 09:45:00'),
