-- Chicago Roofing Authority (7 reviews)
((SELECT id FROM cleaners WHERE slug = 'chicago-roofing-authority'), NULL, 'Dennis Walsh', 'dwalsh@email.com', 5, 'Built for Chicago winters', 'Edward and his team installed a new roof with ice and water shield and proper ventilation. We made it through our first winter with zero ice dam issues. Money well spent.', 'approved', 1, '2025-09-12 10:00:00'),
((SELECT id FROM cleaners WHERE slug = 'chicago-roofing-authority'), NULL, 'Christine Kelly', 'ckelly@email.com', 5, 'Reliable and professional', 'Had our flat garage roof replaced with a modified bitumen system. The crew worked through cold weather and the result is watertight. Great experience.', 'approved', 1, '2025-10-18 14:30:00'),
((SELECT id FROM cleaners WHERE slug = 'chicago-roofing-authority'), NULL, 'Larry Johnson', 'ljohnson@email.com', 4, 'Good siding installation', 'In addition to our roof, they installed new vinyl siding. Both projects were coordinated well and the house looks completely refreshed. Minor color matching issue on one panel was fixed.', 'approved', 1, '2025-11-22 09:00:00'),
((SELECT id FROM cleaners WHERE slug = 'chicago-roofing-authority'), NULL, 'Pamela Rodriguez', 'prodriguez@email.com', 5, 'Emergency tarping in a snowstorm', 'A tree branch punched through our roof during a winter storm and their emergency crew was there within an hour. In the snow. They tarped the hole and prevented major water damage.', 'approved', 1, '2025-12-30 17:30:00'),
((SELECT id FROM cleaners WHERE slug = 'chicago-roofing-authority'), NULL, 'Oscar Lee', 'olee@email.com', 5, 'Standing seam metal perfection', 'Beautiful charcoal gray standing seam metal roof on our modern home. The clean lines and quality of the installation are perfect. This roof will outlast us.', 'approved', 1, '2026-01-08 11:00:00'),
((SELECT id FROM cleaners WHERE slug = 'chicago-roofing-authority'), NULL, 'Teresa Cooper', 'tcooper@email.com', 4, 'Solid gutter replacement', 'Replaced all our gutters and downspouts with oversized seamless aluminum. The new system handles heavy rain much better. Good value and professional installation.', 'approved', 1, '2026-01-22 13:30:00'),
((SELECT id FROM cleaners WHERE slug = 'chicago-roofing-authority'), NULL, 'Vincent Murphy', 'vmurphy@email.com', 5, 'Best roofer in Chicagoland', 'Edward''s company has now done three roofing projects for me across different properties. Consistently excellent work, competitive pricing, and they truly stand behind their warranty.', 'approved', 1, '2026-02-05 10:00:00'),

-- Austin Home Renovations (7 reviews)
((SELECT id FROM cleaners WHERE slug = 'austin-home-renovations'), NULL, 'Rachel Foster', 'rfoster@email.com', 5, 'Complete home transformation', 'Jose and his team renovated our 1970s ranch house into a modern open-concept gem. They used sustainable materials and the energy efficiency improvements are already saving us money.', 'approved', 1, '2025-09-05 10:00:00'),
((SELECT id FROM cleaners WHERE slug = 'austin-home-renovations'), NULL, 'Tyler Adams', 'tadams@email.com', 5, 'ADU construction experts', 'They built a beautiful 450 sq ft accessory dwelling unit in our backyard. Perfect for rental income and the construction quality is the same as a full-size home.', 'approved', 1, '2025-10-15 14:15:00'),
((SELECT id FROM cleaners WHERE slug = 'austin-home-renovations'), NULL, 'Megan Clark', 'mclark@email.com', 5, 'Open concept conversion', 'Removed a load-bearing wall between our kitchen and living room and the transformation is incredible. The structural beam was handled perfectly and the space feels huge now.', 'approved', 1, '2025-11-20 11:30:00'),
((SELECT id FROM cleaners WHERE slug = 'austin-home-renovations'), NULL, 'Brandon Davis', 'bdavis@email.com', 4, 'Great renovation company', 'Renovated two bathrooms and a laundry room. Quality work throughout with attention to detail. Minor delay on tile delivery but otherwise a smooth process.', 'approved', 1, '2025-12-18 09:00:00'),
((SELECT id FROM cleaners WHERE slug = 'austin-home-renovations'), NULL, 'Olivia Martin', 'omartin@email.com', 5, 'Sustainable building experts', 'Love that they focus on green building practices. They used reclaimed wood, low-VOC paints, and energy-efficient windows throughout our renovation. The house is healthier and greener.', 'approved', 1, '2026-01-10 13:45:00'),
((SELECT id FROM cleaners WHERE slug = 'austin-home-renovations'), NULL, 'Nathan White', 'nwhite2@email.com', 4, 'Solid work on our addition', 'Added a sunroom and master closet to our home. The work is high quality and the addition integrates seamlessly. Budget ran slightly over due to material cost increases.', 'approved', 1, '2026-01-28 10:15:00'),
((SELECT id FROM cleaners WHERE slug = 'austin-home-renovations'), NULL, 'Sophia Johnson', 'sjohnson@email.com', 5, 'Highly recommend', 'Jose and his team are honest, talented, and professional. Our whole-house renovation was a huge undertaking and they managed it beautifully. Our Austin home is now our forever home.', 'approved', 1, '2026-02-10 15:30:00');

